var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오르카 씨!! 괜찮아요? 눈 좀 떠 봐요!","JPN":"オルカさん！！　大丈夫ですか？　目を開けてください！","ENG":"Orca!! Are you all right?! Wake up!","TWN":"奧爾卡！！你沒事吧？你醒一醒！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"안심하시길. 당분간 안정을 취하면 깨어나실 겁니다.","JPN":"ご安心を。しばらくすると目覚めるでしょう。","ENG":"Don't worry. She'll be fine if you let her rest for a while.","TWN":"請放心，她很快就會醒來的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 최근 뵈었을 때보다 놀랄 만큼 강해지셨군요. 그 자 말대로.","JPN":"ですが、この前会った時より驚くほどに強くなられましたね。あの者の言うとおり。","ENG":"But she's become much stronger since the last time I saw her. Just like he said.","TWN":"不過他說的沒錯，確實比最近一次看到時更厲害。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 자라니……? 그 사람이 베로니카 씨에게 이런 짓을 하라고 요구한 건가요?","JPN":"あの者……？　その人がベロニカさんにこんなことをするよう仕向けたのですか？","ENG":"Who are you talking about...? Is he the person who asked you to do this, Miss Veronica?","TWN":"他是誰……？是那個人要求你做這種事的嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아뇨. 사장님을 찾아뵈러 온 건 순전히 제 판단이랍니다.","JPN":"いいえ。社長を訪ねたのはひとえに私の判断です。","ENG":"No. It was my decision to come and see Boss.","TWN":"不，來找老闆是我個人的決定。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이만 자리를 피해 주세요. 여기 오래 머무르시면 위험한 일에 휘말릴 수 있습니다.","JPN":"もうこの場からお離れください。長くとどまれば危険なことに巻き込まれるかもしれません。","ENG":"Now, please leave the area. You'll also be in danger if you stay here for too long.","TWN":"請趕緊離開，你若繼續待在這裡，恐怕會捲入危險之中。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"기다려요, 베로니카 씨!","JPN":"待ってください、ベロニカさん！","ENG":"Miss Veronica, wait!","TWN":"等一下，貝洛妮卡！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"뭔가 협박당하고 계신 거라면 사장님께서 도와 주실 거예요.","JPN":"誰かに脅迫されているのでしたら、社長が助けてくださるはずです。","ENG":"If you're being threatened, I'm sure Boss can help you.","TWN":"是不是有人威脅你？老闆一定會幫你的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 솔직하게 말씀해 주세요. 모네 양이 이 일을 알면 슬퍼하지 않겠어요?","JPN":"だからありのままに話してください。モネさんがこのことを知ったら悲しむと思いませんか？","ENG":"So please, just tell me the truth. Think about how Mone would feel is she heard about this.","TWN":"你就老實說吧。況且莫妮要是知道這件事，你覺得她不會難過嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……저는 이만 집무실로 가야 하니, 오르카 씨를 부탁드리겠습니다.","JPN":"……私はもう執務室へ向かわないといけませんので、オルカさんをよろしくお願いいたします。","ENG":"...I must head to the office now. Please take care of Orca for me.","TWN":"……我現在要去辦公室，奧爾卡就麻煩了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 모쪼록, 평안하시길.","JPN":"それでは、どうかご自愛ください。","ENG":"Then, I bid you farewell.","TWN":"請務必要平安無事。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"요점만 말씀하세요. 제게 뭘 원하시는 거죠?","JPN":"要点だけお話しください。私に何を求めているのですか？","ENG":"Just cut to the chase. What do you want from me?","TWN":"請說重點吧，你想要我做什麼？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"간단해. 아버지의 집무실에 숨겨진 통로가 있을 걸세.","JPN":"簡単なことさ。父の執務室に、隠し通路があるはずだ。","ENG":"It's simple. There's a hidden pathway in Father's office.","TWN":"很簡單，爸爸的辦公室裡應該有個秘密通道。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 아버지라고 부를 수 있는 분은 제가 아는 한 한 분밖에 없습니다.","JPN":"ご主人様を父と呼べる方は、私の知っている限りお一人だけです。","ENG":"There's only one person I know who can say Father to Master.","TWN":"能夠稱呼主人爸爸的，據我所知就只有一位。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 야속하군. 마음에 들진 않아도 일단은 한 핏줄이나 마찬가지인데.","JPN":"はは、悲しいな。気に入らなくても一応は同じ血筋なんだが。","ENG":"Haha! How heartless. But even if you don't like it, I am still his flesh and blood.","TWN":"哈哈，真是冷血，不過就算你不喜歡，但血脈相連是事實。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"집무실 통로 끝에는 외부와 철저하게 단절된 공간이 존재한다네.","JPN":"執務室の通路の先には外部と徹底的に切り離された空間が存在している。","ENG":"Once you reach the end of the path, there will be a space that is completely cut off from the outside world.","TWN":"辦公室通道的盡頭，有一個與世隔絕的空間。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그 안에 있는 장치에 내가 말해 준 암호를 입력하면 모든 문제가 해결될 거야.","JPN":"その中にある装置に私が教えたパスワードを入力すれば万事が解決されるはずだ。","ENG":"There, enter the password I told you into the device, and everything will be resolved.","TWN":"只要在那裡面的裝置上輸入我告訴你的密碼，一切的問題就能迎刃而解。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"어째서 제가 그런 허무맹랑한 이야기를 믿고 따를 거라고 확신하시는지 모르겠군요.","JPN":"なぜ私がそのような話を信じて従うと思われるのでしょうか。","ENG":"I'm not sure why you're so certain that I'll believe in such nonsense.","TWN":"你為何確定我會相信那種荒謬的事並且照做呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 해코지하기 위한 흉계라고 받아들이는 것이 일반적일 텐데요.","JPN":"ご主人様に害をなす企みとして受け取るのが普通ではないでしょうか。","ENG":"It sounds like you want me to get involved in your ploy to harm Master.","TWN":"一般人都會認為，這是要加害主人的計謀吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"믿으라고 한 적 없어. 검은 평의회의 의장이 하는 말인데, 당연히 신중을 기해 확인해야지.","JPN":"信じろとは言っていない。黒の評議会の議長の言葉だ、当然慎重になるべきだろう。","ENG":"I never asked you to believe me. But as it is coming from Chairman of the Dark Council, you should proceed with caution.","TWN":"我從未要你相信，但這是黑暗評議會議長說的話，為求慎重當然要確認囉。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그쪽이 직접 확인하고도 행동에 나서지 않는다면, 그건 이미 내 손을 떠난 일이야.","JPN":"直接確認した後に行動するかしないかは、そちらで決めてもらって構わない。","ENG":"If you don't act after seeing it for yourself, then it's already out of my hands.","TWN":"若你親自確認完畢後還是不行動，那就不是我所能控制的。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그렇게 필요한 일이라면, 당신 부하들을 부려도 되지 않습니까?","JPN":"それほどに必要なことでしたら、あなたの部下を使ってもいいのではないですか？","ENG":"If you so desperately need this done, why not get one of your henchmen to do it?","TWN":"既然是那麼重要的事，為何不叫你的手下去做呢？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"나는 박애주의자라네. 아까운 목숨들을 사지로 떠밀 생각은 없어.","JPN":"私は博愛主義者でね。貴重な人員を死地へ行かせるつもりはない。","ENG":"I'm a philanthropist. I don't wish to put precious lives at risk.","TWN":"我是博愛主義者，我不希望寶貴的人命去送死。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마담이 최고의 꽃이라고 칭찬한 자네이기에 이렇게 자리를 만들어 제안한 거지.","JPN":"マダムが最高の花だと褒めていた君だから、こうやって機会を作って提案したのさ。","ENG":"I'm proposing this offer to you because madam kept mentioning how you were her best flower.","TWN":"而你是最受到夫人稱讚的花，我才會向你提出這個建議。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"비록…… 목숨은 장담할 수 없겠지만.","JPN":"……命の保証はしかねるがな。","ENG":"Even if... I can't guarantee you'll come out alive.","TWN":"雖然……不保證性命無虞。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};